{
  "verses": [
    {
      "n": 2,
      "column": "left",
      "text": "Tas trefchajs Absaloms Dehls bija Iskijus/ ta Dehls bi-\nMaëkas Dehls/ Talmaja ta ja Manaffus.\nRehnixa no Gesura Mettas.\nTas zettortajs Adonijus Agi-\ntas Dehls."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Tas peektajs Sewatjus/\nno Abitulas/ tas festajs Jetre-\nams/ no winna Seewas Eglas."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Schee teschi irr winnam\nEebronā dsimmufchi/ jo winſch\nwaldija tur feptinus Gaddus\nun teschus Mehneſchus/ un trihs-\ndefinitis un trihs Gaddus wal-\nDija winſch Jerusaleme."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Un schee irr winnam Je-\nrusaleme dsimmufchi/ Simeüs\nun Sobabs/ un Nahtans/ un\nSalaimans tee tschetri/no Batsu-\nas Anuniēta Meitas."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Jebears/ un Elisaimus/ un\nFeliwelets."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un Nogus/ un Newegs/\nun Japius."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un Eelisamus/ un Eeltja-\ndus/ un Eeliwalets tee dewint."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Schee wiffi irr Dahvida\nBehrni/ bes to leeku Seewu\nBehrneem. Un Tahmara btja\nwinno Mahfa."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un Salaimana Dehls bi-\nja Rekabeams/ ta Dehls bija\nAbtjus/ ta Dehls btja Ahus/ ta\nDehls bija Josawats."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Ta Dehls btja Jorams/\nta Dehls bija Atasjus/ ta Dehls\nbija Joas."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ta Dehls btja Amazijus/\nta Dehls bija Asartjus/ ta Dehls\nbija Jotams."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Ta Dehls btja Akas/ ta ja/ Odajus/ Elijasibs/ un Pla-\njus/"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Ta Dehls bija Amons/\nta Dehls bija Josijus."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un Josijus Behrni bija/\nJoanans tas pirmdsimnis/ Joja-\nkims tas ohtrs/ Zidekijus tas tre-\nchajs/ Sallums tas zettortajs."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Jojakima Behrni bija\nJekantjus/ ta Dehls bija Ze-\ndekijus."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Un Jekanijus/ ( kas Zee-\ntuma bijis/) Behrni bija/ Se-\naltiels winna Dehls."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Malkirams/ un Wa-\ndajus/ un Senneazars/ un Je-\nkamajus/Osamus un Nedabijus."
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un Wadajus Behrm bi-\nja Zernbabels un Simejus. Un\nZerubabeļa Behrni bija Mesul-\nlams/ un Anantjus/ un Selo-\nmite winnu Mahfa."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Asubus/ un Dēls/ un\nBerektjus/ un Asadtjus/ Jusab-\nEses/ tee peezi."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un Anantjus Behrni bt-\nja/Plattijus un Jesajus / tee\nBehrni Rewajns/ tee Behrni\nArnava/ tee Behrni Obadijus/\ntee Behrni Sakantjus."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un tee Behrni Sakanti-\nus bija Semajus. Un Sema-\njus Behrni bija Atus/ un Ji-\nzeals/un Bariaēs/ un Nearijus/\nun Sawats/ Sesus tee teschi."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un Nearijus Behrni bi-\nja Elioenajus / un Jskijus/ un\nAsrikans/ tee trihs."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un Elioenajus Behrni bi-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
